query {
  viewer {
    scope: zones(filter: { zoneTag: "" }) {
      topHostnames: httpRequestsAdaptiveGroups(limit: 1) {
        count
      }
    }
  }
}

query {
  viewer {
    scope: zones(filter: { zoneTag: "" }) {
      violations: httpRequestsAdaptiveGroups(limit: 1) {
        count
      }
    }
  }
}

query($zoneTag: String!, $datetimeStart: DateTime!, $datetimeEnd: DateTime!) {
  viewer {
    scope: zones(filter: { zoneTag: $zoneTag }) {
      topHostnames: httpRequestsAdaptiveGroups(
        limit: 5000
        orderBy: [count_DESC]
        filter: {
          AND: [
            {
              datetime_geq: $datetimeStart
              datetime_leq: $datetimeEnd
            }
            { requestSource: "eyeball" }
            { edgeResponseStatus_geq: 200 }
            { edgeResponseStatus_lt: 400 }



          ]
        }
      ) {
        count
        dimensions {
          clientRequestHTTPHost
        }
      }
    }
  }
}

query($zoneTag: String!, $datetimeStart: DateTime!, $datetimeEnd: DateTime!) {
  viewer {
    scope: zones(filter: { zoneTag: $zoneTag }) {
      violations: httpRequestsAdaptiveGroups(
        limit: 5000
        orderBy: [count_DESC]
        filter: {
          AND: [
            {
              datetime_geq: $datetimeStart
              datetime_leq: $datetimeEnd
            }
            { edgeResponseStatus_geq: 200 }
            { edgeResponseStatus_lt: 400 }
            { requestSource: "eyeball" }




          ]
        }
      ) {
        count
        dimensions {
          clientRequestPath
          clientRequestHTTPHost

        }
      }
    }
  }
}
